```bash
# Build all
cargo build --all

# Test all
cargo test --all

# Lint
cargo clippy --all
cargo fmt --all

# Python bindings
cd crates/pybos && maturin develop

# Node.js bindings
cd crates/jsbos && npm install && npm run build
