118: /// Thread-safe circuit breaker implementation.
119: #[derive(Debug)]
120: pub struct CircuitBreaker {
121:     config: CircuitBreakerConfig,
122:     failures: Arc<AtomicUsize>,
123:     last_failure_time: Arc<Mutex<Option<Instant>>>,
124:     state: Arc<Mutex<CircuitState>>,
125:     /// Counter for half-open probe attempts.
126:     probe_count: Arc<AtomicU64>,
127: }
128: 
129: impl CircuitBreaker {
130:     /// Create a new circuit breaker with the given configuration.
131:     pub fn new(config: CircuitBreakerConfig) -> Self {
132:         Self {
133:             config,
134:             failures: Arc::new(AtomicUsize::new(0)),
135:             last_failure_time: Arc::new(Mutex::new(None)),
136:             state: Arc::new(Mutex::new(CircuitState::Closed)),
137:             probe_count: Arc::new(AtomicU64::new(0)),
138:         }
139:     }
140: 
141:     /// Check if a request is allowed. Returns Ok(()) if allowed, Err(CircuitOpen) if blocked.
142:     fn lock_state(&self) -> std::sync::MutexGuard<'_, CircuitState> {
143:         self.state
144:             .lock()
145:             .unwrap_or_else(|poisoned| poisoned.into_inner())
146:     }
147: 
148:     fn lock_last_failure_time(&self) -> std::sync::MutexGuard<'_, Option<Instant>> {
149:         self.last_failure_time
150:             .lock()
151:             .unwrap_or_else(|poisoned| poisoned.into_inner())
152:     }
153: 
154:     pub fn check(&self) -> Result<(), ResilienceError<()>> {
155:         let mut state = self.lock_state();
156:         let now = Instant::now();
157: 
158:         match *state {
159:             CircuitState::Closed => {
160:                 let failures = self.failures.load(Ordering::Relaxed);
161:                 if failures >= self.config.max_failures {
162:                     *state = CircuitState::Open;
163:                     *self.lock_last_failure_time() = Some(now);
164:                     log::warn!(
165:                         "[CircuitBreaker] Too many failures ({}), opening circuit",
166:                         failures
167:                     );
168:                     return Err(ResilienceError::CircuitOpen);
169:                 }
170:                 Ok(())
171:             }
172:             CircuitState::Open => {
173:                 let last_failure = self.lock_last_failure_time();
174:                 if let Some(last) = *last_failure {
175:                     if now.duration_since(last) >= self.config.cooldown {
176:                         *state = CircuitState::HalfOpen;
177:                         log::info!("[CircuitBreaker] Cooldown elapsed, entering half-open state");
178:                         return Ok(());
179:                     }
180:                 }
181:                 Err(ResilienceError::CircuitOpen)
182:             }
183:             CircuitState::HalfOpen => {
184:                 let count = self.probe_count.fetch_add(1, Ordering::Relaxed);
185:                 if count.is_multiple_of(3) {
186:                     Ok(())
187:                 } else {
188:                     Err(ResilienceError::CircuitOpen)
189:                 }
190:             }
191:         }
192:     }
193: 
194:     /// Record a successful call. Resets failure count in Closed state.
195:     pub fn record_success(&self) {
196:         let mut state = self.lock_state();
197:         match *state {
198:             CircuitState::Closed => {
199:                 self.failures.store(0, Ordering::Relaxed);
200:             }
201:             CircuitState::HalfOpen => {
202:                 *state = CircuitState::Closed;
203:                 self.failures.store(0, Ordering::Relaxed);
204:                 self.probe_count.store(0, Ordering::Relaxed);
205:                 log::info!("[CircuitBreaker] Recovery successful, circuit closed");
206:             }
207:             CircuitState::Open => {}
208:         }
209:     }
210: 
211:     /// Record a failed call. Increments failure count and may open the circuit.
212:     pub fn record_failure(&self) {
213:         let mut state = self.lock_state();
214:         let now = Instant::now();
215: 
216:         match *state {
217:             CircuitState::Closed => {
218:                 let count = self.failures.fetch_add(1, Ordering::Relaxed) + 1;
219:                 *self.lock_last_failure_time() = Some(now);
220:                 if count >= self.config.max_failures {
221:                     *state = CircuitState::Open;
222:                     log::warn!(
223:                         "[CircuitBreaker] Failure threshold reached ({}), opening circuit",
224:                         count
225:                     );
226:                 }
227:             }
228:             CircuitState::HalfOpen => {
229:                 *state = CircuitState::Open;
230:                 *self.lock_last_failure_time() = Some(now);
231:                 log::warn!("[CircuitBreaker] Probe failed, reopening circuit");
232:             }
233:             CircuitState::Open => {
234:                 *self.lock_last_failure_time() = Some(now);
235:             }
236:         }
237:     }
238: 
239:     /// Get current state (for observability).
240:     pub fn get_state(&self) -> CircuitState {
241:         *self.lock_state()
242:     }
243: }
