257: /// Thread-safe rate limiter using sliding window algorithm.
258: /// Tracks individual request timestamps for more accurate rate limiting.
259: #[derive(Debug)]
260: pub struct RateLimiter {
261:     config: RateLimiterConfig,
262:     /// Sorted timestamps of recent requests (oldest first).
263:     timestamps: Arc<Mutex<VecDeque<Instant>>>,
264: }
265: 
266: impl RateLimiter {
267:     fn lock_timestamps(&self) -> std::sync::MutexGuard<'_, VecDeque<Instant>> {
268:         self.timestamps
269:             .lock()
270:             .unwrap_or_else(|poisoned| poisoned.into_inner())
271:     }
272: 
273:     /// Create a new rate limiter with the given configuration.
274:     pub fn new(config: RateLimiterConfig) -> Self {
275:         Self {
276:             config,
277:             timestamps: Arc::new(Mutex::new(VecDeque::new())),
278:         }
279:     }
280: 
281:     /// Try to acquire a slot. Returns Ok(()) if allowed, Err(RateLimited) if exhausted.
282:     /// Automatically waits and retries if rate limited.
283:     pub async fn acquire(&self) -> Result<(), ResilienceError<()>> {
284:         let max_retries = 3;
285:         let base_backoff = Duration::from_millis(500);
286: 
287:         for attempt in 0..max_retries {
288:             let result = self.try_acquire();
289:             if result.is_ok() {
290:                 return Ok(());
291:             }
292: 
293:             if attempt < max_retries - 1 {
294:                 let backoff = base_backoff * (1 << attempt).min(6);
295:                 let reset_at = self.reset_at();
296:                 let wait_time = if let Some(reset) = reset_at {
297:                     let now = Instant::now();
298:                     if reset > now {
299:                         reset.duration_since(now)
300:                     } else {
301:                         backoff
302:                     }
303:                 } else {
304:                     backoff
305:                 };
306:                 log::info!(
307:                     "[RateLimiter] Waiting {:?} for rate limit reset (attempt {}/{})",
308:                     wait_time,
309:                     attempt + 1,
310:                     max_retries
311:                 );
312:                 tokio::time::sleep(wait_time).await;
313:             }
314:         }
315: 
316:         Err(ResilienceError::RateLimited)
317:     }
318: 
319:     fn try_acquire(&self) -> Result<(), ResilienceError<()>> {
320:         let mut timestamps = self.lock_timestamps();
321:         let now = Instant::now();
322:         let window = self.config.window;
323: 
324:         while let Some(oldest) = timestamps.front() {
325:             if now.duration_since(*oldest) >= window {
326:                 timestamps.pop_front();
327:             } else {
328:                 break;
329:             }
330:         }
331: 
332:         let current_count = timestamps.len() as u32;
333:         if current_count >= self.config.capacity {
334:             log::warn!(
335:                 "[RateLimiter] Rate limit exceeded (capacity: {}, window: {:?})",
336:                 self.config.capacity,
337:                 window
338:             );
339:             return Err(ResilienceError::RateLimited);
340:         }
341: 
342:         timestamps.push_back(now);
343:         Ok(())
344:     }
345: 
346:     pub fn remaining(&self) -> u32 {
347:         let timestamps = self.lock_timestamps();
348:         let now = Instant::now();
349:         let window = self.config.window;
350: 
351:         let valid_count = timestamps
352:             .iter()
353:             .filter(|t| now.duration_since(**t) < window)
354:             .count() as u32;
355:         self.config.capacity.saturating_sub(valid_count)
356:     }
357: 
358:     /// Get window reset time (for observability).
359:     pub fn reset_at(&self) -> Option<Instant> {
360:         let timestamps = self.lock_timestamps();
361:         timestamps
362:             .front()
363:             .map(|oldest| *oldest + self.config.window)
364:     }
365: }
