403:     /// Execute an async function with resilience checks.
404:     /// Checks rate limiter first (with auto-wait), then circuit breaker, then executes the function.
405:     /// Automatically retries on transient errors (429, timeout).
406:     pub async fn execute<F, Fut, T, E>(&self, mut op: F) -> Result<T, ResilienceError<E>>
407:     where
408:         F: FnMut() -> Fut,
409:         Fut: std::future::Future<Output = Result<T, E>>,
410:         E: std::fmt::Debug,
411:     {
412:         let max_retries = self.rate_limit_config.max_retries;
413:         let base_backoff = Duration::from_millis(500);
414: 
415:         for attempt in 0..=max_retries {
416:             // Rate limit check - use acquire() to wait when about to exceed
417:             if let Some(limiter) = &self.rate_limiter {
418:                 if limiter.acquire().await.is_err() {
419:                     if attempt < max_retries {
420:                         let duration = base_backoff * (1 << attempt).min(6);
421:                         tokio::time::sleep(duration).await;
422:                         continue;
423:                     }
424:                     return Err(ResilienceError::RateLimited);
425:                 }
426:             }
427: 
428:             // 2) Circuit breaker check
429:             if let Some(breaker) = &self.circuit_breaker {
430:                 match breaker.check() {
431:                     Ok(()) => {}
432:                     Err(ResilienceError::CircuitOpen) => return Err(ResilienceError::CircuitOpen),
433:                     Err(ResilienceError::RateLimited) => {
434:                         let duration = base_backoff * (1 << attempt).min(6);
435:                         tokio::time::sleep(duration).await;
436:                         continue;
437:                     }
438:                     Err(ResilienceError::Inner(())) => {}
439:                 }
440:             }
441: 
442:             // 3) Execute the operation
443:             let result = op().await;
444: 
445:             // 4) Check for transient error and retry
446:             let is_transient = match &result {
447:                 Err(e) => {
448:                     let err_str = format!("{:?}", e);
449:                     err_str.contains("429")
450:                         || err_str.contains("Too Many Requests")
451:                         || err_str.contains("timeout")
452:                 }
453:                 _ => false,
454:             };
455: 
456:             if is_transient && attempt < max_retries {
457:                 let duration = base_backoff * (1 << attempt).min(6);
458:                 tokio::time::sleep(duration).await;
459:                 continue;
460:             }
461: 
462:             // 5) Record outcome in circuit breaker
463:             if let Some(breaker) = &self.circuit_breaker {
464:                 match &result {
465:                     Ok(_) => breaker.record_success(),
466:                     Err(_) => breaker.record_failure(),
467:                 }
468:             }
469: 
470:             return result.map_err(ResilienceError::Inner);
471:         }
472: 
473:         Err(ResilienceError::RateLimited)
474:     }
